// ── Inertia tensor verification ──────────────────────────────────────────────

/// JSBSim J3 Cub inertia values (slug*ft2 converted to kg*m2).
///
/// Source: J3Cub.xml mass_balance section.
///   Ixx = 538.01 slug*ft2 = 729.4 kg*m2
///   Iyy = 386.81 slug*ft2 = 524.4 kg*m2
///   Izz = 871.03 slug*ft2 = 1181.0 kg*m2
///   Mass = 902.22 lb = 409.2 kg
const JSBSIM_IXX: f64 = 538.01 * 1.35582;
const JSBSIM_IYY: f64 = 386.81 * 1.35582;
const JSBSIM_IZZ: f64 = 871.03 * 1.35582;
const JSBSIM_MASS_KG: f64 = 902.22 * 0.453592;

/// Verify that Avian's auto-computed mass properties from J3 Cub zone
/// colliders are in the right ballpark compared to JSBSim.
///
/// This test spawns the aircraft, runs a few frames for Avian to compute
/// mass properties, and prints the comparison. The current collider layout
/// is a simplified approximation (cuboids), so we allow generous tolerances
/// and primarily use this for visibility rather than hard pass/fail.
#[test]
fn j3cub_inertia_comparison() {
    let mut app = App::new();

    app.add_plugins(MinimalPlugins)
        .add_plugins(bevy::transform::TransformPlugin)
        .add_plugins(bevy::asset::AssetPlugin::default())
        .add_plugins(PhysicsPlugins::default())
        .add_plugins(AircraftFdmPlugin::default());

    app.insert_resource(TimeUpdateStrategy::ManualDuration(Duration::from_secs_f64(
        1.0 / 60.0,
    )));

    app.add_systems(Startup, |mut commands: Commands| {
        let initial_rot = Quat::from_rotation_x(std::f32::consts::FRAC_PI_2);
        j3cub::spawn(
            &mut commands,
            Transform::from_xyz(0.0, 300.0, 0.0).with_rotation(initial_rot),
        );
    });

    app.finish();

    // Run a few frames so Avian computes mass properties from colliders.
    for _ in 0..5 {
        app.update();
    }

    // Read computed mass properties.
    let mut found = false;
    let world = app.world_mut();
    let mut query = world.query::<(
        &ComputedMass,
        &ComputedAngularInertia,
        &ComputedCenterOfMass,
    )>();

    for (mass, inertia, com) in query.iter(&world) {
        found = true;
        let m = mass.value() as f64;
        let (principal, local_frame) = inertia.principal_angular_inertia_with_local_frame();

        // Reconstruct body-frame inertia tensor from principal axes + rotation.
        // I_body = R * diag(principal) * R^T
        let r = bevy::math::Mat3::from_quat(local_frame);
        let p = [principal.x as f64, principal.y as f64, principal.z as f64];
        let mut ib = [[0.0f64; 3]; 3];
        for i in 0..3 {
            for j in 0..3 {
                for k in 0..3 {
                    let ri = [r.x_axis[i] as f64, r.y_axis[i] as f64, r.z_axis[i] as f64];
                    let rj = [r.x_axis[j] as f64, r.y_axis[j] as f64, r.z_axis[j] as f64];
                    ib[i][j] += ri[k] * p[k] * rj[k];
                }
            }
        }
        let ixx = ib[0][0];
        let iyy = ib[1][1];
        let izz = ib[2][2];

        println!("\n-- J3 Cub Inertia Comparison (body frame) -------------------");
        println!(
            "  {:>20} {:>10} {:>10} {:>8}",
            "", "Avian", "JSBSim", "Ratio"
        );
        println!(
            "  {:>20} {:10.1} {:10.1} {:8.2}",
            "Mass (kg)",
            m,
            JSBSIM_MASS_KG,
            m / JSBSIM_MASS_KG
        );
        println!(
            "  {:>20} {:10.1} {:10.1} {:8.2}",
            "Ixx (kg*m2)",
            ixx,
            JSBSIM_IXX,
            ixx / JSBSIM_IXX
        );
        println!(
            "  {:>20} {:10.1} {:10.1} {:8.2}",
            "Iyy (kg*m2)",
            iyy,
            JSBSIM_IYY,
            iyy / JSBSIM_IYY
        );
        println!(
            "  {:>20} {:10.1} {:10.1} {:8.2}",
            "Izz (kg*m2)",
            izz,
            JSBSIM_IZZ,
            izz / JSBSIM_IZZ
        );
        println!("  {:>20} {:?}", "CG offset (m)", com.0);
        println!("------------------------------------------------------------");

        // Mass within 5%
        let mass_ratio = m / JSBSIM_MASS_KG;
        assert!(
            mass_ratio > 0.95 && mass_ratio < 1.05,
            "Mass off: {m:.1} kg (target: {JSBSIM_MASS_KG:.1} kg, ratio: {mass_ratio:.2})"
        );
        // Inertia within 15% (body-frame, after rotation)
        let ixx_ratio = ixx / JSBSIM_IXX;
        let iyy_ratio = iyy / JSBSIM_IYY;
        let izz_ratio = izz / JSBSIM_IZZ;
        assert!(
            ixx_ratio > 0.85 && ixx_ratio < 1.15,
            "Ixx off: {ixx:.0} (target: {JSBSIM_IXX:.0}, ratio: {ixx_ratio:.2})"
        );
        assert!(
            iyy_ratio > 0.85 && iyy_ratio < 1.15,
            "Iyy off: {iyy:.0} (target: {JSBSIM_IYY:.0}, ratio: {iyy_ratio:.2})"
        );
        assert!(
            izz_ratio > 0.85 && izz_ratio < 1.15,
            "Izz off: {izz:.0} (target: {JSBSIM_IZZ:.0}, ratio: {izz_ratio:.2})"
        );
    }

    assert!(found, "No aircraft entity found with mass properties");
}

// ── Emergent pitch-damping measurement ───────────────────────────────────────

/// Measure emergent Cmq by comparing the aero pitch torque at zero vs
/// non-zero pitch rate. The delta isolates the pitch-rate-dependent
/// contribution.
///
/// The J3 Cub does not use LodDamping. Pitch damping emerges from
/// per-zone local-angle corrections: `delta_alpha = -q * x / V` at each
/// zone, which increases h-stab alpha during pitch-up, producing a
/// nose-down restoring moment.
///
/// Datcom target: Cmq = -6/rad.
/// Expected emergent: Cmq ~ -10/rad (no downwash lag).
#[test]
fn j3cub_emergent_cmq() {
    fn build_app(pitch_rate_world_z: f32) -> App {
        let mut app = App::new();
        app.add_plugins(MinimalPlugins)
            .add_plugins(bevy::transform::TransformPlugin)
            .add_plugins(bevy::asset::AssetPlugin::default())
            .add_plugins(PhysicsPlugins::default())
            .add_plugins(AircraftFdmPlugin::default());
        app.insert_resource(TimeUpdateStrategy::ManualDuration(Duration::from_secs_f64(
            1.0 / 60.0,
        )));
        let q = pitch_rate_world_z;
        app.add_systems(Startup, move |mut commands: Commands| {
            let initial_rot = Quat::from_rotation_x(std::f32::consts::FRAC_PI_2);
            let root = j3cub::spawn(
                &mut commands,
                Transform::from_xyz(0.0, 300.0, 0.0).with_rotation(initial_rot),
            );
            commands
                .entity(root)
                .insert(LinearVelocity(Vec3::new(27.0, 0.0, 0.0)))
                // Body pitch rate q maps to world Z due to spawn rotation_x(PI/2).
                .insert(AngularVelocity(Vec3::new(0.0, 0.0, q)));
        });
        app.finish();
        app
    }

    let mut baseline = build_app(0.0);
    let q_rads_f32 = 5.0_f32.to_radians();
    let mut perturbed = build_app(q_rads_f32);

    // Run 5 frames: Avian init + flight_state update + aero forces.
    for _ in 0..5 {
        baseline.update();
    }
    for _ in 0..5 {
        perturbed.update();
    }

    // Read ConstantTorque (total aero torque on the root body, world frame).
    let read_torque = |app: &mut App| -> Vec3 {
        let world = app.world_mut();
        let mut query = world.query::<&ConstantTorque>();
        query
            .iter(&world)
            .next()
            .expect("no ConstantTorque found")
            .0
    };

    let t_base = read_torque(&mut baseline);
    let t_pert = read_torque(&mut perturbed);

    // Body pitch torque = world Z torque (due to spawn rotation).
    // Negative means nose-down restoring moment.
    let delta_mz = (t_pert.z - t_base.z) as f64;

    // Back out Cmq: delta_M = Cmq * (q * c / (2V)) * qbar * S * c
    let q_rad = q_rads_f32 as f64;
    let v = 27.0_f64;
    let rho = 1.19_f64; // ~ISA at 300 m
    let qbar = 0.5 * rho * v * v;
    let s = 16.584_f64;
    let c = 1.6_f64;
    let norm = (q_rad * c / (2.0 * v)) * qbar * s * c;
    let cmq_measured = delta_mz / norm;

    let datcom_cmq = -6.0_f64;

    println!("\n-- Emergent Cmq Measurement --------------------------------");
    println!("  Baseline pitch torque (q=0):     {:.1} N*m", t_base.z);
    println!("  Perturbed pitch torque (q=5d/s): {:.1} N*m", t_pert.z);
    println!("  Delta pitch torque:              {:.1} N*m", delta_mz);
    println!(
        "  Measured Cmq:                    {:.2} /rad",
        cmq_measured
    );
    println!("  Datcom target:                   {:.1} /rad", datcom_cmq);
    println!(
        "  Ratio (measured/Datcom):          {:.2}",
        cmq_measured / datcom_cmq
    );
    println!("------------------------------------------------------------");

    // Cmq should be negative (restoring).
    assert!(
        cmq_measured < 0.0,
        "Cmq should be negative (restoring), got {cmq_measured:.2}"
    );

    // Should be between 1x and 3x the Datcom value (more negative, no downwash lag).
    assert!(
        cmq_measured < datcom_cmq,
        "Cmq ({cmq_measured:.1}) should be more negative than Datcom ({datcom_cmq})"
    );
    assert!(
        cmq_measured > datcom_cmq * 3.0,
        "Cmq ({cmq_measured:.1}) should not exceed 3x Datcom ({:.0})",
        datcom_cmq * 3.0
    );
}

/// Verify the startup validation system detects a deliberately broken zone.
/// We spawn an AeroZone with unsorted Table1D breakpoints and confirm the
/// validation system runs without panicking (it logs warnings).
#[test]
fn startup_validation_catches_bad_zone() {
    let mut app = App::new();
    app.add_plugins(MinimalPlugins)
        .add_plugins(bevy::transform::TransformPlugin)
        .add_plugins(bevy::asset::AssetPlugin::default())
        .add_plugins(PhysicsPlugins::default())
        .add_plugins(AircraftFdmPlugin {
            validate_on_startup: true,
        });

    app.insert_resource(TimeUpdateStrategy::ManualDuration(Duration::from_secs_f64(
        1.0 / 60.0,
    )));

    // Spawn an aircraft root with a broken child zone.
    app.add_systems(Startup, |mut commands: Commands| {
        commands
            .spawn(AircraftCoreBundle {
                transform: Transform::from_xyz(0.0, 100.0, 0.0),
                ..Default::default()
            })
            .with_children(|parent| {
                parent.spawn(AeroZoneBundle {
                    zone: AeroZone {
                        // Deliberately unsorted breakpoints.
                        cl: AeroCoeff::Table1D {
                            breakpoints: vec![0.3, 0.0, -0.3],
                            values: vec![1.0, 0.0, -1.0],
                        },
                        cd: AeroCoeff::Scalar(0.01),
                        area_m2: 2.0,
                        chord_m: 0.5,
                        ..Default::default()
                    },
                    collider: Collider::cuboid(0.5, 2.0, 0.02),
                    ..Default::default()
                });
            });
    });

    app.finish();

    // Run a few frames: PostStartup validation runs after Startup.
    // Should NOT panic, only log warnings.
    for _ in 0..3 {
        app.update();
    }

    // If we got here, validation ran without crashing. The actual warnings
    // are logged via bevy::log and not captured in the test, but the
    // unit tests in aero_coeff.rs verify the validation logic itself.
}
